@startuml
skinparam classAttributeIconSize 0
skinparam shadowing false
skinparam roundcorner 12
skinparam linetype ortho

skinparam class {
  BackgroundColor #F2F2F2
  BorderColor #222222
  FontColor #000000
}

skinparam interface {
  BackgroundColor #F2F2F2
  BorderColor #222222
  FontColor #000000
}

class Client

class Context {
  - currentState: State
  + request()
}

interface State {
  + handle()
}

class StateOne {
  + handle()
}

class StateTwo {
  + handle()
}

Client --> Context

Context o--> State

StateOne ..|> State
StateTwo ..|> State

@enduml
